INSERT INTO RECENZIJA (RecenzijaID, Ocjena, Komentar, DatumRecenzije, NarudzbaID) VALUES
                                                                                      ('b8000001-0000-0000-0000-000000000001', 5, 'Odlična usluga, rublje besprijekorno izglačano i na vrijeme preuzeto. Toplo preporučujem!',    '2024-06-05', 'e5000001-0000-0000-0000-000000000001'),
                                                                                      ('b8000001-0000-0000-0000-000000000002', 4, 'Dobra usluga, rublje uredno izglačano. Jedino bih volio malo brže preuzimanje.',               '2024-06-20', 'e5000001-0000-0000-0000-000000000002'),
                                                                                      ('b8000001-0000-0000-0000-000000000003', 5, 'Fantastično! Zavjese kao nove, jakne savršeno izglačane. Definitivno ću se ponovno naručiti.', '2024-07-15', 'e5000001-0000-0000-0000-000000000003'),
                                                                                      ('b8000001-0000-0000-0000-000000000004', 3, 'Solidna usluga, ali košulje nisu bile baš savršeno izglačane oko ovratnika.',                  '2024-07-25', 'e5000001-0000-0000-0000-000000000004'),
                                                                                      ('b8000001-0000-0000-0000-000000000005', 5, 'Sve pohvale! Jakne i zavjese kao iz praonice, brza dostava i ljubazna komunikacija.',          '2024-10-06', 'e5000001-0000-0000-0000-000000000009');